import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務分析專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6257_矽格/20260430/F05_應收帳款品質與收款天數_財務分析專家.md","filePath":"審計報告庫/財務審計/6257_矽格/20260430/F05_應收帳款品質與收款天數_財務分析專家.md"}'),i={name:"審計報告庫/財務審計/6257_矽格/20260430/F05_應收帳款品質與收款天數_財務分析專家.md"};function o(n,a,s,c,h,d){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="f05-應收帳款品質與收款天數-財務分析專家-審計報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務分析專家 審計報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務分析專家-審計報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務分析專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>應收帳款 (AR) 的規模與週轉天數 (DSO) 變動為何？是否存在客戶拖欠或虛增營收風險？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DSO 88.2天仍偏高，壞帳準備腰斬 45.4%逆迴轉 $5,668萬美化損益，前三大客戶集中度飆至 45.3%，收款品質實質惡化。</li><li><strong>風險評級</strong>：中高</li><li><strong>數據時效</strong>：截至 2025/12/31</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點發現</strong>：DSO 88.2天仍偏高，壞帳準備縮減 45.4%（逆迴轉 $5,668萬），前三大客戶集中度飆至 45.3%。</li><li><strong>診斷見解</strong>：壞帳迴轉利益佔淨利 4.8%，為典型美化損益行為。剔除後本業獲利品質需重新評估。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="dso-實測" tabindex="-1">DSO 實測 <a class="header-anchor" href="#dso-實測" aria-label="Permalink to &quot;DSO 實測&quot;">​</a></h3><ul><li><strong>核心重點</strong>：FY2025 DSO=88.2天，較 FY2024 高點 90.8天改善 2.6天，但仍高於 FY2023 水準。</li><li><strong>深度見解</strong>：DSO 回落主因營收年增 7.5%帶動分母擴大，AR 仍成長 4.5%至 47.4億，並非應收帳款有效控管，營收增速放緩恐再推升 DSO。</li></ul><h3 id="ar-營收比背離趨勢" tabindex="-1">AR/營收比背離趨勢 <a class="header-anchor" href="#ar-營收比背離趨勢" aria-label="Permalink to &quot;AR/營收比背離趨勢&quot;">​</a></h3><ul><li><strong>核心重點</strong>：AR/營收比 24.2%，營收年增 7.5%的同時 AR 仍增 4.5%，呈「雙緩增」格局，略高於 FY2023 基準 24.0%。</li><li><strong>深度見解</strong>：AR 與營收同步放緩，暫未見「放帳衝業績」特徵，但集中度攀升需警惕。</li></ul><h3 id="壞帳準備與帳齡品質" tabindex="-1">壞帳準備與帳齡品質 <a class="header-anchor" href="#壞帳準備與帳齡品質" aria-label="Permalink to &quot;壞帳準備與帳齡品質&quot;">​</a></h3><ul><li><strong>核心重點</strong>：FY2025 備抵呆帳從 $13,061萬降至 $7,134萬（-45.4%），帳面逾期帳款佔比降至 1.62%。</li><li><strong>深度見解</strong>：壞帳準備縮減幅度遠超帳齡改善，提列標準明顯偏寬鬆。$5,668萬迴轉利益佔稅後淨利 4.8%，為明確的美化損益信號。</li></ul><h3 id="客戶集中度與信用風險" tabindex="-1">客戶集中度與信用風險 <a class="header-anchor" href="#客戶集中度與信用風險" aria-label="Permalink to &quot;客戶集中度與信用風險&quot;">​</a></h3><ul><li><strong>核心重點</strong>：前三大客戶營收佔比從 29.9%飆升至 45.3%（+15.45pp），客戶甲獨佔 22.3%。</li><li><strong>深度見解</strong>：45.3% 集中度在封測產業屬高風險水位，客戶甲需求放緩或付款週期拉長將直接衝擊現金流，為結構性風險。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：壞帳準備逆向迴轉 $5,668萬確認為利益，佔稅後淨利 4.8%。若剔除此迴轉利益，FY2025 實質稅後淨利為 $11.17億而非 $11.74億，EPS 從 $2.20 下修至 $2.09。此為明確的「會計美化」信號，未來若客戶信用惡化需大幅回補提列，將對損益造成雙重打擊。</li><li><strong>空頭風險二</strong>：前三大客戶營收集中度從 29.9%飆升至 45.3%，已觸及半導體代工產業的高風險警戒線。矽格作為封測代工廠，若主要客戶（尤其佔 22.3%的客戶甲）訂單波動或轉單，營收與現金流將同步承壓。同時，高集中度意味著公司在議價與收款條件上對大客戶的談判籌碼有限，進一步壓縮 DSO 改善空間。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — 帳務數據 (AccountsReceivableNet, Revenue) 以 <code>數據採集器.py</code> 分別取得 finance/balance_sheet/revenue，數據一致</li><li><strong>yfinance</strong>: 未使用（矽格為上櫃股票，yfinance 台股覆蓋有限）</li><li><strong>年報/法說</strong>: OK — 2025_Q4 及 2024_Q4 合併財務報告，帳齡分析（第35頁）、備抵損失變動表（第34/64頁）、重要客戶資訊（第71/72頁）均已核對</li><li><strong>關鍵核對碼</strong>： <ul><li>AR帳齡：未逾期 98.38% / 逾期30天 1.21% / 31-90天 0.19% / 91-180天 0.03% / 181天+ 0.19%（FY2025第35頁）</li><li>備抵損失：$7,134萬（FY2025）vs $13,061萬（FY2024），迴轉 $5,668萬（第12頁綜合損益表）</li><li>客戶集中度：甲 22.33% + 丁 11.57% + 乙 11.44% = 45.34%（第71頁）</li></ul></li></ul>',21)])])}const g=e(i,[["render",o]]);export{u as __pageData,g as default};
